import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { getEventById, getSlotsByEvent } from '../../api/api';
import { useAuth } from '../../context/AuthContext';
import toast from 'react-hot-toast';

const TYPE_COLORS = { MOVIE:'var(--blue)', CONCERT:'var(--gold)', EVENT:'var(--green)' };

const EventDetailPage = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const { user } = useAuth();
  const [event, setEvent] = useState(null);
  const [slots, setSlots] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedDate, setSelectedDate] = useState('');

  useEffect(() => {
    const load = async () => {
      try {
        const [evRes, slRes] = await Promise.all([getEventById(id), getSlotsByEvent(id)]);
        setEvent(evRes.data.data);
        const sl = slRes.data.data || [];
        setSlots(sl);
        if (sl.length>0) setSelectedDate(sl[0].showDate);
      } catch { toast.error('Failed to load event'); }
      finally { setLoading(false); }
    };
    load();
  }, [id]);

  if (loading) return <div className="loading-center"><div className="spinner" /></div>;
  if (!event) return <div className="empty-state"><h3>Event not found</h3></div>;

  const dates = [...new Set(slots.map(s=>s.showDate))].sort();
  const filteredSlots = selectedDate ? slots.filter(s=>s.showDate===selectedDate) : slots;
  const tc = TYPE_COLORS[event.type] || 'var(--accent)';

  return (
    <div style={{ background:'var(--bg-primary)', minHeight:'100vh' }}>
      {/* Hero */}
      <div style={{ background:'linear-gradient(135deg, #fff8f5 0%, #fef2ea 100%)', borderBottom:'1.5px solid var(--border)', padding:'28px 0 32px' }}>
        <div className="container">
          <button onClick={()=>navigate(-1)} className="btn btn-ghost btn-sm" style={{ marginBottom:'16px', paddingLeft:0 }}>← Back to Browse</button>
          <div style={{ display:'flex', gap:'20px', alignItems:'flex-start', flexWrap:'wrap' }}>
            <div style={{ width:90, height:90, background:'white', borderRadius:'16px', border:'1.5px solid var(--border)', display:'flex', alignItems:'center', justifyContent:'center', fontSize:'40px', boxShadow:'var(--shadow)', flexShrink:0 }}>
              {event.type==='MOVIE'?'🎬':event.type==='CONCERT'?'🎵':'🎪'}
            </div>
            <div style={{ flex:1 }}>
              <div style={{ display:'flex', gap:'8px', marginBottom:'10px', flexWrap:'wrap' }}>
                <span className={`badge ${event.status==='ACTIVE'?'badge-success':'badge-danger'}`}>{event.status}</span>
                <span className="badge badge-info">{event.type}</span>
                {event.genre && <span className="badge badge-muted">{event.genre}</span>}
                {event.language && <span className="badge badge-muted">{event.language}</span>}
              </div>
              <h1 style={{ fontFamily:'var(--font-display)', fontSize:'clamp(1.6rem,3vw,2.6rem)', fontWeight:400, marginBottom:'8px' }}>{event.name}</h1>
              {event.summary && <p style={{ color:'var(--text-secondary)', lineHeight:1.7, maxWidth:'600px', fontSize:'15px' }}>{event.summary}</p>}
              <div style={{ display:'flex', gap:'24px', marginTop:'14px', flexWrap:'wrap' }}>
                {event.duration && <Detail label="Duration" value={event.duration} />}
                {event.categoryName && <Detail label="Category" value={event.categoryName} />}
              </div>
            </div>
          </div>
        </div>
      </div>

      <div className="container" style={{ paddingTop:'32px' }}>
        <h2 style={{ fontFamily:'var(--font-display)', fontSize:'1.8rem', fontWeight:400, marginBottom:'20px' }}>Choose a Show</h2>
        {slots.length===0 ? (
          <div className="empty-state"><div className="empty-state-icon">📅</div><h3>No Shows Scheduled</h3><p style={{ fontSize:'13px' }}>Check back later</p></div>
        ) : (
          <>
            {/* Date Tabs */}
            <div style={{ display:'flex', gap:'8px', marginBottom:'24px', overflowX:'auto', paddingBottom:'4px' }}>
              {dates.map(date=>(
                <button key={date} onClick={()=>setSelectedDate(date)} style={{ padding:'10px 20px', borderRadius:'10px', border:'1.5px solid', borderColor:selectedDate===date?'var(--accent)':'var(--border)', background:selectedDate===date?'var(--accent-dim)':'var(--bg-card)', color:selectedDate===date?'var(--accent)':'var(--text-secondary)', cursor:'pointer', transition:'var(--transition)', flexShrink:0, fontFamily:'var(--font-body)', fontWeight:600, fontSize:'13px', boxShadow:'var(--shadow-sm)' }}>
                  {new Date(date).toLocaleDateString('en-IN',{weekday:'short',day:'numeric',month:'short'})}
                </button>
              ))}
            </div>
            <div style={{ display:'grid', gridTemplateColumns:'repeat(auto-fill, minmax(200px,1fr))', gap:'14px', paddingBottom:'40px' }}>
              {filteredSlots.map(slot=>(
                <SlotCard key={slot.slotId} slot={slot} onBook={()=>{
                  if (!user){toast.error('Please login');navigate('/login');return;}
                  navigate(`/book/${slot.slotId}`);
                }} />
              ))}
            </div>
          </>
        )}
      </div>
    </div>
  );
};

const SlotCard = ({ slot, onBook }) => {
  const isAvailable = slot.slotStatus==='AVAILABLE';
  const isHousefull = slot.slotStatus==='HOUSEFULL';
  return (
    <div className="card" style={{ padding:'18px' }}>
      <div style={{ marginBottom:'10px' }}>
        <div style={{ fontFamily:'var(--font-display)', fontSize:'1.6rem', fontWeight:400, color:'var(--text-primary)' }}>{slot.startTime?.slice(0,5)}</div>
        <div style={{ fontSize:'12px', color:'var(--text-muted)' }}>ends {slot.endTime?.slice(0,5)}</div>
      </div>
      {slot.location && <div style={{ fontSize:'12px', color:'var(--text-secondary)', marginBottom:'12px', fontWeight:500 }}>📍 {slot.location.locName}</div>}
      <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center' }}>
        <span style={{ fontSize:'12px', fontWeight:700, color:isAvailable?'var(--green)':isHousefull?'var(--gold)':'var(--text-muted)' }}>
          {isAvailable?`${slot.seatsLeft} left`:slot.slotStatus}
        </span>
        <button onClick={onBook} disabled={!isAvailable} className="btn btn-primary btn-sm" style={{ opacity:isAvailable?1:0.5 }}>
          {isHousefull?'Full':'Book'}
        </button>
      </div>
    </div>
  );
};

const Detail = ({ label, value }) => (
  <div>
    <div style={{ fontSize:'11px', color:'var(--text-muted)', textTransform:'uppercase', letterSpacing:'0.6px', fontWeight:600 }}>{label}</div>
    <div style={{ fontSize:'14px', fontWeight:700, marginTop:'2px', color:'var(--text-primary)' }}>{value}</div>
  </div>
);

export default EventDetailPage;
